CREATE OR REPLACE FUNCTION fpb_tel_get_share_in_rec ( as_recno char ) RETURNS bigint AS $body$
DECLARE

ldc_share sc_com_m_receipt_item.balance%type;

BEGIN
      SELECT sc_com_m_receipt_item.balance
      INTO STRICT ldc_share
      FROM sc_com_m_receipt_item
      WHERE ( sc_com_m_receipt_item.item_type_id in ( 'SL' ,'SB' ) ) AND ( sc_com_m_receipt_item.receipt_no = as_recno );
      if coalesce(ldc_share::text, '') = '' then ldc_share := 0;end if;
  RETURN ldc_share;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
